INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (1416, 192073, 2, 1053, '客家流沙之�{事', '�{字在常用汉语中是极少见的，因此院墟的八里坪人对外人说起自已家乡的�{时，不得不禅述再三。这个�{字，是九年制义务教育的课本上永远不会出现的。一种特定的语言在特定的环境中产生，除了上四乡人，不会再有人对这个�{字有着特别强烈的体会。它是一种用米碾成粉做成的食物，偶然有叫马蛋、白�@等类似食品，但与八里坪的�{比起来，其品种之繁多、风味之奇特，都是无法相比拟的。91年版的《客家风情》一书，和95增版的《客家风情》，在那些以洋洋洒洒数万言语叙述的客家食谱中，对�{的叙述是少而又少。一个院墟人不了解客家的�{，就彷佛中文系的学生不懂张爱玲；�{象一个沉默的孩子，进入客家大厅后从未说话。 
<br>
<br>          有朋友对我说过很多东西往往徒有其名，比如闽西八大干中好几干已在市面上销声匿迹、北京烤鸭油腻难吃，曾有读者向池莉投诉――武汉小吃不若其描写的精彩上口；或者口感不同，或者厨者手艺不够精到。又如一些慕名客家擂茶的朋友，对我说将乐的正宗擂茶是多么的令他们失望。我没品尝过将乐擂茶，但院墟的擂茶，我是从小就喝的，好喝得很。 
<br>
<br>           ――永安及闽中许多地方都可以吃到叫�@条、或锅边糊的小吃，在院墟，人们形象的称之为�{皮――扁且薄。是将米桨在蒙布的簸箕或竹筛中摇匀了，放入大锅蒸几分钟即熟，将筛从蒸汽腾腾的锅中替换出，四指分捏两角，迅速将布提出，倒覆于厨板，用手背轻蹭，将�{皮剥离，分段的撒上酸菜或香菇冬笋熟碎料，用刀划分了，一一裹卷，用汤匙背抹香油，便成为美味的簸箕�{了；也可以将�{皮剥在室外骄阳高照的干净稻草上，待晒硬了，剪成几箩大小不一的方块，等农闲时，细铁沙爆炒，那�{皮便膨起，不带半粒铁沙，香脆可口，味道极似旺旺雪饼，且绝不腻人。院墟的甘美擂茶配着香酥的�{皮，曾令江西的妇女亲戚们落下一个可爱的谚语：江西嬷食BANG唔食茶。 
<br>
<br>           某天和朋友谈起�{，粗略一数，居然有二十几种！过大年通常用的是红糖煎�{和芋线咸�{，可吃一个正月。元宵来临，孩子们提着竹篮在春意盎然中四野掐白头翁草的嫩尖，做出来的叫艾�{。粗叶麻为料作成的通体碧绿的叫粗叶�{；细滑上口，清香盈齿。小孩子出生，作父母的早早为幼年的孩子酝酿一个良好的朋友氛围, 四处散发清淡的安名�{,不加半点调味剂,不知是否暗符了了君子之交淡如水的古朴?新酒出坛不加半点水的酒酿和成的芳香醉人的漉汤�{。简单明快磨沙口味的搅浆米�{。形状扭曲口感筋韧的蛙子�{，沾不同的料，最叫人饱食。山上烧成的狗木灰作碱料做成的蒸笼�{，一整个�{答，随割随煮，可刨成细粉状，也可切成不厚不薄的条形，配上屋檐下的腊肉，再扯一些蒜叶，会吃辣的加上些小米椒，炒起来浓香四溢，细碎入味，哪还需饭哟；其同样作成的黄�{砣，柔软粘筷，需用筷子圈裹了沾料，有些人对上了味口后，会嗜之如狂，譬如老八古之嗜好鸡鸭屁股，光明佬之嗜好雪芋头。还有冬天关起厨门来石磨细细磨成的烙�{，讲究层次的千层�{，甚至还有苦日子时用喂猪的糠作成的糠�{……所有这些，都是用米碾成粉做成的，或简单如山西扯面片，或讲究色形味俱佳――粳米粉和糯米粉的搭配，水的调和，揉的劲道，表皮的顺滑。没有粉碎机器时，那些粉都是在矮矮的碓房下用碓马一下一下把米碓成粉的，利用的是杠杆原理，碓马是木制的，马腰上有踏水车似的扶手横梁，马嘴以硬铁包就，米则放在埋设的石臼里，人在碓马的臀部位置踩，让马头抬起，一松劲，马嘴便借助重力碓在石臼中，一家子齐心协力，碓房矣乃有声，其乐融融。八里坪人每到年二九、三十，家家户户都是团在餐桌边，或撮粉团的，或左右开弓捏�{的，到处放置的竹筛和簸箕排满了等待下油锅的白乎乎�{。最先煎成的那家上供香案后，必定招呼四邻先尝尝，有还在做�{没空的，则让小孩子装了一大泥碗送去，客气中一把倒在满是白粉的簸箕中，让正做�{的人边吃边捏。油锅煎�{时，有�{团粘细粒的，或带太多水分，则会膨胀爆锅，沸油应声溅起，操捞爪的家长得赶紧烧香――疑心灶君生气了。 
<br>
<br>           一般来说�{讲究的是松软。但也有例外，如岩前的煎�{就是以坚硬耐啃出名，乒乓球大小的圆�{，团得结实又炸得老透，走山路时口袋放上两个，可以啃上十五华里。有人形容它象铁蛋，打得死人――曾有被圆�{打死人的传闻，有说是正夏大中午时打在人家的人中打死的，也有的说其实是讹传，那人见圆�{急速飞来，头猛的一偏，不料后脑勺正好撞在一支穿透木板的铁钉上，就死了。想来后者较有说服力，但圆�{的坚硬由此可见一斑。 
<br>
<br>           �{还有它的衍生产品，切成细如尾指炸得硬却又香酥的，叫�@子，也分甜咸两味；还有切成三角状的，加了茴香、八角粉、柑皮干，更是蓬松酥口，嘎嘣脆的咀嚼声会有一种食欲的互动。从江西客家亲戚回来的兴古，还带回一种更为精致的做法，他能把�@子作成各种花草鸟兽状，油炸后不散脱，更是惟妙惟肖，金黄诱人。许多“福佬鬼”刚开始尝院墟的�{、�@子时，都是有一种本能的抵触心理，说是油炸的火气太大，吃多了受不了，但呆的时间稍长一些，没事时抓上一些慢慢吃，却会情不自禁的迷恋上，而且脸上也未见疙瘩出现――不少人回到城里后才会恍然大悟，在院墟喝的是山里的竹叶水，什么火气降不下去呢！ 
<br>
<br>           现在的企业正悄悄兴起午间餐。�{是不是也是因为类似的想法而产生的呢？在八里坪生产队的年代，有专门送田地午间餐的习惯，最常吃的就是�{，因为它简单，无需太多碗筷，手抓即食。在上山伐木、打猎，或采摘香菇红菇等山货时，也是口袋装几条�{配山涧甘泉充饥。上四乡的各姓族谱究其根源，似乎都是商周以来的贵族后裔，语言中多少还带些远古如“�喻采薄钡恼铰移�息，或者说，这是不是以前为了作战而发明的类似于压缩饼干的功效呢？――这一切，现今已是无从考证了。', '�{字在常用汉语中是极少见的，因此院墟的八里坪人对外人说起自已家乡的�{时，不得不禅述再三。这个�{字，是九年制义务教育的课本上永远不会出现的。一种特定的语言在特定的环境中产生，除了上四乡人，不会再有人对这个�{字有着特别强烈的体会。它是一种用米碾成粉做成的食物，偶然有叫马蛋、白�@等类似食品，但与八里坪的�{比起来，其品种之繁多、风味之奇特，都是无法相比拟的。91年版的《客家风情》一书，和95增版的《客家风情》，在那些以洋洋洒洒数万言语叙述的客家食谱中，对�{的叙述是少而又少。一个院墟人不了解客家的�{，就彷佛中文系的学生不懂张爱玲；�{象一个沉默的孩子，进入客家大厅后从未说话。

